9781	  /**
9782	   * Helper: post a writ, spawn a rig, advance the first engine to running
9783	   * with an active animator session. Returns both writ and rig.
9784	   */
9785	  async function spawnRunningRig(opts?: { parentId?: string }) {
9786	    const { clerk, spider, stacks } = fix;
9787	    const writ = opts?.parentId
9788	      ? await clerk.post({ title: 'Child writ', body: 'child', parentId: opts.parentId })
9789	      : await postWrit(clerk);
9790	
9791	    // If the writ is in 'waiting' state (parent added a child), we need to
9792	    // transition it through to ready first — but the clerk handles that via
9793	    // post() which transitions parent to waiting and sets child to ready.
9794	    // For a standalone writ, status is 'ready'.
9795	
9796	    await spider.crawl(); // spawn rig
9797	
9798	    const book = rigsBook(stacks);
9799	    const rigs = await book.find({ where: [['writId', '=', writ.id]], limit: 1 });
9800	    const rig = rigs[0];
9801	
9802	    // Mark draft as completed so implement can launch
9803	    const updatedEngines = rig.engines.map((e: EngineInstance) =>
9804	      e.id === 'draft'
9805	        ? { ...e, status: 'completed' as const, yields: { draftId: 'd1', codexName: 'c', branch: 'b', path: '/p' } }
9806	        : e,
9807	    );
9808	    await book.patch(rig.id, { engines: updatedEngines });
9809	
9810	    // Launch implement (creates session)
9811	    await spider.crawl(); // engine-started
9812	
9813	    const [rigAfterStart] = await book.find({ where: [['writId', '=', writ.id]], limit: 1 });
9814	    const implEngine = rigAfterStart.engines.find((e: EngineInstance) => e.id === 'implement');
9815	
9816	    // Override the auto-completed session to be running
9817	    if (implEngine?.sessionId) {
9818	      const sessBook = stacks.book<SessionDoc>('animator', 'sessions');
9819	      await sessBook.patch(implEngine.sessionId, { status: 'running', endedAt: undefined });
9820	    }
9821	
9822	    const freshWrit = await clerk.show(writ.id);
9823	    return { writ: freshWrit, rig: rigAfterStart };
9824	  }
