9828	    const { clerk, stacks, cancelCalls } = fix;
9829	    const { writ, rig } = await spawnRunningRig();
9830	
9831	    // Cancel the writ
9832	    await clerk.transition(writ.id, 'cancelled');
9833	
9834	    // Rig should now be cancelled
